// ── MOON PHASE SVG ──
// Σχεδιάζει το σωστό σχήμα φεγγαριού με clip-path geometry.
// Χρησιμοποιεί δύο ημικύκλια: ένα για τη φωτισμένη πλευρά, ένα ellipse για τη σκιά.
// Υπολογισμός lit path βάσει phase string
// Ακολουθεί την ίδια λογική με το button-card offset map:
// new=40, wax_cres=25, first_q=10, wax_gib=-10, full=-40, wan_gib=-10, last_q=10, wan_cres=25
// offset = cos(2π*phase)*r  → new(0)=+r, full(0.5)=-r
// Μετατρέπουμε το string σε offset απευθείας
function _moonLitPath(phase, r, cx, cy, fraction) {
  // Use continuous fraction if provided, else fall back to discrete phase map
  const phaseMap = {
    'new_moon': 0, 'waxing_crescent': 0.125, 'first_quarter': 0.25,
    'waxing_gibbous': 0.375, 'full_moon': 0.5, 'waning_gibbous': 0.625,
    'last_quarter': 0.75, 'waning_crescent': 0.875,
  };
  const p = (fraction != null) ? ((fraction % 1) + 1) % 1 : (phaseMap[phase] ?? 0.5);

  const isNew  = p < 0.015 || p > 0.985;
  const isFull = p > 0.485 && p < 0.515;

  if (isNew)  return `M${cx},${cy} Z`;
  if (isFull) return `M${cx},${cy-r} A${r},${r} 0 1,1 ${cx},${cy+r} A${r},${r} 0 1,1 ${cx},${cy-r} Z`;

  const QUARTER_BOW = 0.14;
  const terminator  = Math.cos(2 * Math.PI * p);
  const tx          = Math.max(r * QUARTER_BOW, Math.abs(terminator) * r);
  const isWaxing    = p < 0.5;
  let sweep = isWaxing
    ? (terminator > 0 ? 0 : 1)
    : (terminator > 0 ? 1 : 0);
  if (Math.abs(terminator) < QUARTER_BOW) sweep = isWaxing ? 1 : 0;

  if (isWaxing) {
    return `M${cx},${cy-r} A${r},${r} 0 0,1 ${cx},${cy+r} A${tx},${r} 0 0,${sweep} ${cx},${cy-r} Z`;
  } else {
    return `M${cx},${cy-r} A${r},${r} 0 0,0 ${cx},${cy+r} A${tx},${r} 0 0,${sweep} ${cx},${cy-r} Z`;
  }
}

